const input = $input.first().json;
const telefono = (input.telefono || '').toString().trim();

if (!telefono) {
  throw new Error('telefono es requerido');
}
if (!/^\d{10}$/.test(telefono)) {
  throw new Error(`telefono invalido: '${telefono}' — se esperan 10 digitos sin prefijo`);
}

return [{ json: { telefono } }];

const items = $input.all();

const perfiles = items
  .map(i => i.json)
  .filter(p => p.ahorrista_id != null)
  .map(p => ({
    ...p,
    // hitos puede venir como string JSON desde Postgres
    hitos: typeof p.hitos === 'string' ? JSON.parse(p.hitos) : (p.hitos || [])
  }));

const total = perfiles.length;

return [{ json: {
  total_encontrados: total,
  perfiles,
  perfil: total === 1 ? perfiles[0] : null,
  caso: total === 0 ? 'sin_perfil'
      : total === 1 ? 'perfil_unico'
      : 'multiples_planes'
} }];

const err = $input.first();
const msg = err?.json?.message || err?.json?.error?.message || 'Telefono invalido o no proporcionado';
return [{ json: {
  caso: 'error',
  tipo: 'validacion',
  mensaje: msg
} }];

const err = $input.first();
const msg = err?.json?.message || err?.json?.error?.message || 'Error al consultar la base de datos';
return [{ json: {
  caso: 'error',
  tipo: 'db',
  mensaje: msg
} }];
